// Title: Risky Sign-In From Unknown Device and Rarely Used IP
// Author: Benjamin Zulliger (github.com/benscha/KQLAdvancedHunting)
// Source: https://www.kqlsearch.com/query/Risky%20Sign%20In%20From%20Unkown%20Device%20And%20Rarely%20Used%20Ip
// MITRE: T1078.004 - Cloud Accounts
// Collected: 2026-05-10
// KQL Hunter - https://github.com/sivolko/kql-hunter

// Define corporate network range to exclude internal traffic
let CorporateIPRange = "0.0.0.0/16";
// Define the timeframe for historical analysis
let LookbackHistory = 29d;
// Set reference point to the beginning of the current day
let TodayStart = startofday(now());
// Identify users with suspicious behavior within the detection window
let AffectedUsers = materialize(
    BehaviorAnalytics
    | where TimeGenerated > ago(4h)
    | where not(ipv4_is_in_range(SourceIPAddress, CorporateIPRange))
    | where isnotempty(UserPrincipalName)
    | where ActivityType != "FailedLogOn"
    | where ActivityInsights.FirstTimeUserConnectedFromDevice == true
    | join kind=inner (
        IdentityInfo
        | summarize arg_max(TimeGenerated, *) by AccountUpn
        | project AccountUpn, TenantMembershipType
    ) on $left.UserPrincipalName == $right.AccountUpn
    | where TenantMembershipType == "Member"
    | distinct UserPrincipalName
);
// Retrieve historical IP usage for the identified users
let HistoricalIPs =
    EntraIdSignInEvents
    | where TimeGenerated between ((TodayStart - LookbackHistory) .. (TodayStart - 1ms))
    | where AccountUpn in (AffectedUsers)
    | where ErrorCode == 0
    | summarize DistinctDaysSeenFromIP = dcount(bin(TimeGenerated, 1d))
        by AccountUpn, IPAddress
    | project UserPrincipalName = AccountUpn, SourceIPAddress = IPAddress, DistinctDaysSeenFromIP;
// Main query
BehaviorAnalytics
| where TimeGenerated > ago(4h)
| where not(ipv4_is_in_range(SourceIPAddress, CorporateIPRange))
| where isnotempty(UserPrincipalName)
| where ActivityType != "FailedLogOn"
| where ActivityInsights.FirstTimeUserConnectedFromDevice == true
| join kind=inner hint.strategy=broadcast (
    IdentityInfo
    | summarize arg_max(TimeGenerated, *) by AccountUpn
    | project AccountUpn, TenantMembershipType
) on $left.UserPrincipalName == $right.AccountUpn
| where TenantMembershipType == "Member"
| extend SourceDeviceLower = tolower(SourceDevice)
| join kind=leftouter (
    DeviceInfo
    | extend DeviceNameLower = tolower(DeviceName)
    | project DeviceNameLower, DeviceName, DeviceId, OnboardingStatus
) on $left.SourceDeviceLower == $right.DeviceNameLower
| where OnboardingStatus != "Onboarded" or isempty(OnboardingStatus)
| join kind=leftouter hint.strategy=broadcast (HistoricalIPs) on UserPrincipalName, SourceIPAddress
| extend IPRiskClassification = case(
    isempty(DistinctDaysSeenFromIP), "High Risk - New IP",
    DistinctDaysSeenFromIP < 3,       "Medium Risk - Infrequent IP",
    "Low Risk"
)
| where IPRiskClassification != "Low Risk"
| summarize arg_max(TimeGenerated, *) by UserPrincipalName
| where isempty(DeviceName)
| where DistinctDaysSeenFromIP < 2

// Title: Detection Rule Usefulness Evaluation (DOVE Model)
// Author: Sergio Albea
// Source: https://www.kqlsearch.com/query/Detection%20Rule%20Usefulness%20Evaluation%20Based%20On%20Dove%20Model
// Collected: 2026-05-10
// KQL Hunter - https://github.com/sivolko/kql-hunter
//
// Evaluates detection overlap by finding alerts that fire on the same assets
// within the same hour from multiple detection sources (DOVE Model).

AlertInfo
| join kind=inner AlertEvidence on AlertId
| extend DateHour = bin(Timestamp, 1h)
| summarize
    Group_Alert_Titles = make_set(Title),
    Different_Detection_Sources = make_set(DetectionSource),
    Number_Detection_Sources = dcount(DetectionSource)
    by DateHour, AccountUpn, EmailSubject, FileName, DeviceName, RemoteIP, RemoteUrl, Application
| where Number_Detection_Sources > 1
    and Different_Detection_Sources contains "Custom detection"
    and (
        isnotempty(AccountUpn) or isnotempty(RemoteIP) or isnotempty(EmailSubject)
        or isnotempty(DeviceName) or isnotempty(RemoteUrl) or isnotempty(Application)
    )
| order by Number_Detection_Sources desc

// Title: Copilot Jailbreak Detected
// Author: Alex Verboon
// Source: https://www.kqlsearch.com/query/Copilot%20-%20Jailbreakdetected
// MITRE ATLAS: AML.T0054 - LLM Jailbreak
// Collected: 2026-05-10
// KQL Hunter - https://github.com/sivolko/kql-hunter

// Query 1: Detect jailbreak via JailbreakDetected flag in message data
CopilotActivity
| where RecordType == "CopilotInteraction"
| extend LLMData = parse_json(LLMEventData)
| mv-expand Message = LLMData.Messages
| extend JailbreakDetected = tobool(Message.JailbreakDetected)
| where JailbreakDetected == true
| order by TimeGenerated desc

