// Title: Git Abuse High Fidelity — Repository Tampering Correlation
// Author: Ali Hussein
// Source: https://www.kqlsearch.com/query/Gitabusehighfidelity
// Collected: 2026-05-10
// KQL Hunter - https://github.com/sivolko/kql-hunter
//
// Correlates Git identity changes, commit amendments, force pushes, and
// optional time manipulation on the same device within a 30-minute window.

let GitConfig = DeviceProcessEvents
| where ProcessCommandLine has "git config --local"
| where ProcessCommandLine has_any ("user.name", "user.email")
| project DeviceId, DeviceName, AccountName, GitConfigTime = Timestamp, GitConfigCmd = ProcessCommandLine;
let GitAmend = DeviceProcessEvents
| where ProcessCommandLine has "git commit"
| where ProcessCommandLine has "--amend"
| project DeviceId, AmendTime = Timestamp, AmendCmd = ProcessCommandLine;
let GitPush = DeviceProcessEvents
| where ProcessCommandLine has "git push"
| where ProcessCommandLine has_any ("-f", "--force", "-uf", "--force-with-lease")
| project DeviceId, PushTime = Timestamp, PushCmd = ProcessCommandLine;
let TimeChange = DeviceProcessEvents
| where FileName in~ ("cmd.exe", "powershell.exe", "powershell_ise.exe")
| where ProcessCommandLine has_any ("date ", "time ", "Set-Date")
| project DeviceId, TimeChangeTime = Timestamp, TimeChangeCmd = ProcessCommandLine;
GitConfig
| join kind=inner GitAmend on DeviceId
| join kind=inner GitPush on DeviceId
| join kind=leftouter TimeChange on DeviceId
| where AmendTime between (GitConfigTime .. GitConfigTime + 30m)
| where PushTime between (AmendTime .. AmendTime + 30m)
| where isempty(TimeChangeTime) or TimeChangeTime between (GitConfigTime - 15m .. PushTime + 15m)
| project DeviceName, AccountName, GitConfigTime, GitConfigCmd, AmendTime, AmendCmd,
          PushTime, PushCmd, TimeChangeTime, TimeChangeCmd
| order by PushTime desc

// Title: Privileged RDP Session Source Mismatch
// Author: Benjamin Zulliger (github.com/benscha/KQLAdvancedHunting)
// Source: https://www.kqlsearch.com/query/Privileged%20Rdp%20Session%20Source%20Mismatch
// MITRE: T1078 (Valid Accounts), T1021.001 (Remote Desktop Protocol)
// Collected: 2026-05-10
// KQL Hunter - https://github.com/sivolko/kql-hunter

// Adjust these patterns to match your environment
let ExcludeTerminalServerRegex = @"^tsar[ae][0-9]{3}";
let PrivUserPattern = @"sys[ae]\.[a-z]+";
let PrivRecentUserPattern = @"^sys[ae]\.";
let ExcludedAccountDomains = dynamic(["nt service", "font driver host", "window manager", "nt-autorität", "autorite nt", "nt authority"]);
let ExcludedAccountNames = dynamic(["-", "admin"]);
let ExcludeIPRange1 = "169.254.0.0/16";
let ExcludeIPRange2 = "192.168.0.0/16";
let DetectionWindow = 1h;
let LookbackWindow = 1d;
let MaxTimeDiffSeconds = 3600;
// Map device names to IPs
let DeviceIPs = DeviceNetworkEvents
| where Timestamp > ago(LookbackWindow)
| where isnotempty(DeviceName)
| where not(ipv4_is_in_range(LocalIP, ExcludeIPRange1))
| where not(ipv4_is_in_range(LocalIP, ExcludeIPRange2))
| where LocalIP != "0.0.0.0"
| project DeviceIP_Timestamp = Timestamp, DeviceName, LocalIP;
// Privileged RDP logons within detection window
let PrivLogons = DeviceLogonEvents
| where Timestamp > ago(DetectionWindow)
| where LogonType == "RemoteInteractive"
| where not(DeviceName matches regex ExcludeTerminalServerRegex)
| where AccountName matches regex PrivUserPattern
| where isnotempty(RemoteIP)
| project-rename PrivAccountName = AccountName, LogonTimestamp = Timestamp;
// Correlate and check for source mismatch
PrivLogons
| join kind=inner DeviceIPs on $left.RemoteIP == $right.LocalIP
| extend TimeDiff = abs(datetime_diff('second', LogonTimestamp, DeviceIP_Timestamp))
| where TimeDiff < MaxTimeDiffSeconds
| summarize arg_min(TimeDiff, *) by LogonTimestamp, DeviceName, PrivAccountName, RemoteIP
| join kind=leftouter (
    DeviceLogonEvents
    | where Timestamp > ago(LookbackWindow)
    | where LogonType in ("Interactive", "RemoteInteractive")
    | where AccountDomain !in (ExcludedAccountDomains)
    | where AccountName !in (ExcludedAccountNames)
    | summarize LastLogon = max(Timestamp), RecentUsers = make_set(AccountName, 3) by DeviceName
) on $left.DeviceName1 == $right.DeviceName
| summarize arg_max(LogonTimestamp, *) by DeviceName1, PrivAccountName
| where isnotempty(RecentUsers)
| mv-expand RecentUser = RecentUsers to typeof(string)
| extend UNameshort1 = extract(@"\.(.+)$", 1, PrivAccountName)
| extend UNameshort2 = iif(
    RecentUser matches regex PrivRecentUserPattern,
    extract(@"\.(.+)$", 1, RecentUser),
    strcat(substring(RecentUser, 0, 1), extract(@"\.(.+)$", 1, RecentUser))
)
| summarize MatchFound = countif(UNameshort2 has UNameshort1), arg_max(LogonTimestamp, *) by DeviceName1, PrivAccountName
| where MatchFound == 0
| extend RecentUsersOnSource = strcat_array(RecentUsers, ", ")
| project LogonTimestamp, DeviceName, DeviceName1, PrivAccountName, RemoteIP, RecentUsersOnSource
